const FREE_SHIPPING_THRESHOLD = 99;

export default function OrderSummary({ cart, products, onNavigate }) {
  const subtotal = cart.reduce((sum, item) => {
    const product = products.find((p) => p.id === item.id);
    return sum + (product ? product.price * item.quantity : 0);
  }, 0);

  const shipping = subtotal >= FREE_SHIPPING_THRESHOLD ? 0 : 9.99;
  const total = subtotal + shipping;

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 lg:sticky lg:top-24">
      <h2 className="text-lg font-bold text-slate-900 mb-6">Order Summary</h2>

      <div className="space-y-3 mb-6">
        <div className="flex justify-between text-sm">
          <span className="text-slate-600">Subtotal</span>
          <span className="font-medium text-slate-900">${subtotal.toFixed(2)}</span>
        </div>
        <div className="flex justify-between text-sm">
          <span className="text-slate-600">Shipping</span>
          {shipping === 0 ? (
            <span className="font-medium text-green-600">Free</span>
          ) : (
            <span className="font-medium text-slate-900">${shipping.toFixed(2)}</span>
          )}
        </div>

        {shipping > 0 && (
          <p className="text-xs text-blue-600 bg-blue-50 rounded-lg p-2.5">
            Add ${(FREE_SHIPPING_THRESHOLD - subtotal).toFixed(2)} more for free shipping
          </p>
        )}

        <div className="border-t border-gray-100 pt-4 flex justify-between items-center">
          <span className="font-bold text-slate-900">Total</span>
          <span className="text-2xl font-extrabold text-slate-900">${total.toFixed(2)}</span>
        </div>
      </div>

      <button className="w-full bg-blue-600 hover:bg-blue-500 text-white font-semibold py-3.5 rounded-xl transition-all duration-200 hover:shadow-lg hover:scale-[1.02] active:scale-95 focus:outline-none focus:ring-2 focus:ring-blue-400">
        Checkout →
      </button>

      <p className="text-xs text-center text-slate-400 mt-4 leading-relaxed">
        Secure checkout · Free returns within 30 days
      </p>
    </div>
  );
}
